package com.alsa.alsacleanfleet.service;
import com.alsa.alsacleanfleet.dto.*;import com.alsa.alsacleanfleet.entity.*;import com.alsa.alsacleanfleet.enums.*;import com.alsa.alsacleanfleet.exception.*;import com.alsa.alsacleanfleet.repository.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.*;import java.time.temporal.ChronoUnit;import java.util.*;
@Service @Transactional public class NettoyageService {private final NettoyageRepository repo;private final BusRepository busRepo;private final TypeNettoyageRepository typeRepo;private final UtilisateurRepository userRepo;public NettoyageService(NettoyageRepository r,BusRepository b,TypeNettoyageRepository t,UtilisateurRepository u){repo=r;busRepo=b;typeRepo=t;userRepo=u;}
 @Transactional(readOnly=true)public List<NettoyageResponseDTO> findAll(){return repo.findAll().stream().map(this::dto).toList();}@Transactional(readOnly=true)public NettoyageResponseDTO findById(Long id){return dto(entity(id));}
 @Transactional(readOnly=true)public Map<String,Long> statistics(){return Map.of("total",repo.count(),"enAttente",repo.countByStatut(StatutNettoyage.EN_ATTENTE),"valides",repo.countByStatut(StatutNettoyage.VALIDE),"refuses",repo.countByStatut(StatutNettoyage.REFUSE),"aujourdHui",repo.countByDateNettoyage(LocalDate.now()));}
 public NettoyageResponseDTO create(NettoyageRequestDTO d){Nettoyage n=new Nettoyage();apply(n,d,true);return dto(repo.save(n));}public NettoyageResponseDTO update(Long id,NettoyageRequestDTO d){Nettoyage n=entity(id);apply(n,d,false);return dto(repo.save(n));}public void delete(Long id){repo.delete(entity(id));}
 private void apply(Nettoyage n,NettoyageRequestDTO d,boolean creating){Bus b=busRepo.findById(d.busId()).orElseThrow(()->new ResourceNotFoundException("Bus introuvable"));if(creating&&!Boolean.TRUE.equals(b.getActif()))throw new BusinessException("Un bus inactif ne peut pas recevoir de nettoyage");Utilisateur nettoyeur=userRepo.findById(d.nettoyeurId()).orElseThrow(()->new ResourceNotFoundException("Nettoyeur introuvable"));if(nettoyeur.getRole()!=Role.NETTOYEUR)throw new BusinessException("Le nettoyeur doit avoir le role NETTOYEUR");if(creating&&!Boolean.TRUE.equals(nettoyeur.getActif()))throw new BusinessException("Un utilisateur inactif ne peut pas etre assigne");Utilisateur sup=d.superviseurId()==null?null:userRepo.findById(d.superviseurId()).orElseThrow(()->new ResourceNotFoundException("Superviseur introuvable"));if(sup!=null&&sup.getRole()!=Role.SUPERVISEUR&&sup.getRole()!=Role.ADMINISTRATEUR)throw new BusinessException("Role superviseur invalide");if(d.heureDebut()!=null&&d.heureFin()!=null&&d.heureFin().isBefore(d.heureDebut()))throw new BusinessException("heureFin ne peut pas preceder heureDebut");if(d.statut()==StatutNettoyage.EN_ATTENTE&&(d.dateValidation()!=null||sup!=null))throw new BusinessException("Un nettoyage en attente ne doit pas etre valide");if(d.statut()!=StatutNettoyage.EN_ATTENTE&&(sup==null||d.dateValidation()==null))throw new BusinessException("Superviseur et dateValidation sont obligatoires");n.setBus(b);n.setTypeNettoyage(typeRepo.findById(d.typeNettoyageId()).orElseThrow(()->new ResourceNotFoundException("Type de nettoyage introuvable")));n.setNettoyeur(nettoyeur);n.setSuperviseur(sup);n.setDateNettoyage(d.dateNettoyage());n.setHeureDebut(d.heureDebut());n.setHeureFin(d.heureFin());Integer duration=d.duree();if(duration==null&&d.heureDebut()!=null&&d.heureFin()!=null)duration=(int)ChronoUnit.MINUTES.between(d.heureDebut(),d.heureFin());n.setDuree(duration);n.setRemarqueNettoyeur(d.remarqueNettoyeur());n.setRemarqueSuperviseur(d.remarqueSuperviseur());n.setStatut(d.statut());n.setDateValidation(d.dateValidation());}
 private Nettoyage entity(Long id){return repo.findById(id).orElseThrow(()->new ResourceNotFoundException("Nettoyage introuvable"));}private NettoyageResponseDTO dto(Nettoyage n){Utilisateur s=n.getSuperviseur();return new NettoyageResponseDTO(n.getId(),n.getBus().getId(),n.getBus().getNumeroBus(),n.getTypeNettoyage().getId(),n.getTypeNettoyage().getLibelle(),n.getNettoyeur().getId(),n.getNettoyeur().getPrenom()+" "+n.getNettoyeur().getNom(),s==null?null:s.getId(),s==null?null:s.getPrenom()+" "+s.getNom(),n.getDateNettoyage(),n.getHeureDebut(),n.getHeureFin(),n.getDuree(),n.getRemarqueNettoyeur(),n.getRemarqueSuperviseur(),n.getStatut(),n.getDateValidation());}}
